schemas/failure_mode.schema.json



{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://example.local/schemas/failure_mode.schema.json",
  "title": "FailureMode",
  "type": "object",
  "additionalProperties": false,
  "required": ["failure_mode_id", "version", "matchers", "heal_sequence", "escalation"],
  "properties": {
    "failure_mode_id": {
      "type": "string",
      "minLength": 3,
      "pattern": "^[A-Z0-9_\\-\\.]+$",
      "description": "Stable identifier for this failure mode."
    },
    "version": {
      "type": "string",
      "pattern": "^[0-9]+\\.[0-9]+\\.[0-9]+$",
      "description": "Semver for this FailureMode definition."
    },
    "description": {
      "type": "string",
      "maxLength": 4000
    },
    "enabled": {
      "type": "boolean",
      "default": true
    },
    "priority": {
      "type": "integer",
      "minimum": 0,
      "maximum": 10000,
      "default": 100,
      "description": "Lower number = higher priority when multiple FailureModes match."
    },
    "matchers": {
      "type": "array",
      "minItems": 1,
      "items": { "$ref": "#/$defs/Matcher" },
      "description": "Deterministic, pure predicates over GateResult + normalized evidence metadata."
    },
    "heal_sequence": {
      "$ref": "#/$defs/HealSequence"
    },
    "escalation": {
      "$ref": "#/$defs/Escalation"
    },
    "tags": {
      "type": "array",
      "items": { "type": "string", "maxLength": 64 },
      "uniqueItems": true
    },
    "metadata": {
      "type": "object",
      "additionalProperties": { "type": ["string", "number", "boolean", "null"] }
    }
  },
  "$defs": {
    "Matcher": {
      "type": "object",
      "additionalProperties": false,
      "required": ["all"],
      "properties": {
        "all": {
          "type": "array",
          "minItems": 1,
          "items": { "$ref": "#/$defs/Condition" },
          "description": "All conditions must be true."
        }
      }
    },
    "Condition": {
      "type": "object",
      "additionalProperties": false,
      "required": ["field", "op", "value"],
      "properties": {
        "field": {
          "type": "string",
          "enum": [
            "gate_id",
            "validator_id",
            "exit_code",
            "error_codes_any",
            "error_codes_all",
            "failure_fingerprint",
            "evidence_schema_valid",
            "evidence_kind",
            "evidence_signature"
          ],
          "description": "Restricted fields to keep matching deterministic."
        },
        "op": {
          "type": "string",
          "enum": ["eq", "neq", "in", "not_in", "contains_any", "contains_all", "matches_regex"],
          "description": "Pure operation; no time, no external calls."
        },
        "value": {
          "description": "Operand for the op. For *_codes_* fields use arrays of normalized enums.",
          "oneOf": [
            { "type": "string" },
            { "type": "integer" },
            { "type": "boolean" },
            { "type": "array", "items": { "type": ["string", "integer", "boolean"] }, "minItems": 1 }
          ]
        }
      }
    },
    "HealSequence": {
      "type": "object",
      "additionalProperties": false,
      "required": ["max_attempts", "heal_template_ids"],
      "properties": {
        "max_attempts": {
          "type": "integer",
          "minimum": 1,
          "maximum": 20
        },
        "heal_template_ids": {
          "type": "array",
          "minItems": 1,
          "items": { "$ref": "#/$defs/HealTemplateId" },
          "description": "Strict ordered sequence. Must not be reordered at runtime."
        },
        "template_attempt_limits": {
          "type": "object",
          "additionalProperties": { "type": "integer", "minimum": 1, "maximum": 20 },
          "description": "Optional per-template max attempts, keyed by heal_template_id."
        }
      }
    },
    "HealTemplateId": {
      "type": "string",
      "minLength": 3,
      "pattern": "^[A-Z0-9_\\-\\.]+$"
    },
    "Escalation": {
      "type": "object",
      "additionalProperties": false,
      "required": ["action", "required_evidence"],
      "properties": {
        "action": {
          "type": "string",
          "enum": ["quarantine", "human_review", "halt_pipeline"]
        },
        "required_evidence": {
          "type": "array",
          "minItems": 1,
          "items": { "type": "string", "minLength": 1 },
          "description": "Evidence paths or evidence kinds required before escalating."
        },
        "notes": { "type": "string", "maxLength": 4000 }
      }
    }
  }
}



schemas/heal_template_result.schema.json



{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://example.local/schemas/heal_template_result.schema.json",
  "title": "HealTemplateResult",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "heal_template_id",
    "status",
    "attempt",
    "prereq_checks",
    "evidence_paths",
    "outputs",
    "failure"
  ],
  "properties": {
    "heal_template_id": {
      "type": "string",
      "pattern": "^[A-Z0-9_\\-\\.]+$"
    },
    "status": {
      "type": "string",
      "enum": ["success", "failed", "prereq_violation"]
    },
    "attempt": {
      "type": "integer",
      "minimum": 1,
      "maximum": 100
    },
    "started_at_utc": {
      "type": "string",
      "format": "date-time",
      "description": "Optional. If present, must be UTC ISO-8601. Do not use for matching."
    },
    "ended_at_utc": {
      "type": "string",
      "format": "date-time",
      "description": "Optional. If present, must be UTC ISO-8601. Do not use for matching."
    },
    "prereq_checks": {
      "type": "object",
      "minProperties": 1,
      "additionalProperties": { "type": "boolean" },
      "description": "Template-specific prereq assertions; all values must be boolean."
    },
    "evidence_paths": {
      "type": "array",
      "items": { "type": "string", "minLength": 1 },
      "minItems": 0,
      "uniqueItems": true
    },
    "outputs": {
      "type": "object",
      "additionalProperties": false,
      "required": ["touched_files", "produced_artifacts"],
      "properties": {
        "touched_files": {
          "type": "array",
          "items": { "type": "string", "minLength": 1 },
          "uniqueItems": true
        },
        "produced_artifacts": {
          "type": "array",
          "items": { "type": "string", "minLength": 1 },
          "uniqueItems": true
        }
      }
    },
    "failure": {
      "type": "object",
      "additionalProperties": false,
      "required": ["error_codes", "exit_code"],
      "properties": {
        "error_codes": {
          "type": "array",
          "items": { "type": "string", "pattern": "^[A-Z0-9_\\-\\.]+$" },
          "uniqueItems": true,
          "description": "Normalized enums only. No free-text."
        },
        "exit_code": {
          "type": "integer",
          "minimum": 0
        },
        "message": {
          "type": "string",
          "maxLength": 4000,
          "description": "Optional human-readable message; never used for matching."
        }
      }
    }
  }
}



schemas/heal_sequence_report.schema.json



Produces a single deterministic healed: true|false output for downstream gates.


{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://example.local/schemas/heal_sequence_report.schema.json",
  "title": "HealSequenceReport",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "run_id",
    "gate_id",
    "failure_mode_id",
    "failure_fingerprint",
    "attempt",
    "sequence",
    "healed",
    "termination_reason",
    "required_evidence_present"
  ],
  "properties": {
    "run_id": {
      "type": "string",
      "minLength": 6,
      "description": "Unique per execution run."
    },
    "gate_id": {
      "type": "string",
      "minLength": 3
    },
    "failure_mode_id": {
      "type": "string",
      "pattern": "^[A-Z0-9_\\-\\.]+$"
    },
    "failure_fingerprint": {
      "type": "string",
      "minLength": 16,
      "description": "Hash over normalized (exit_code + validator_id + error_codes)."
    },
    "attempt": {
      "type": "integer",
      "minimum": 1,
      "maximum": 100,
      "description": "Heal-sequence attempt counter for this gate failure."
    },
    "sequence": {
      "type": "object",
      "additionalProperties": false,
      "required": ["ordered_heal_template_ids", "results"],
      "properties": {
        "ordered_heal_template_ids": {
          "type": "array",
          "minItems": 1,
          "items": { "type": "string", "pattern": "^[A-Z0-9_\\-\\.]+$" }
        },
        "results": {
          "type": "array",
          "minItems": 1,
          "items": { "$ref": "heal_template_result.schema.json" },
          "description": "Results in the order executed. Strictly aligned to ordered_heal_template_ids prefix."
        }
      }
    },
    "required_evidence_present": {
      "type": "boolean",
      "description": "True only if FailureMode.escalation.required_evidence (or sequence-required evidence) exists."
    },
    "healed": {
      "type": "boolean",
      "description": "Single downstream boolean: true only if sequence succeeded and post-verification gate rerun passed."
    },
    "termination_reason": {
      "type": "string",
      "enum": [
        "sequence_success",
        "template_failed",
        "prereq_violation",
        "max_attempts_exceeded",
        "unclassifiable_failure_signature",
        "post_verify_gate_failed",
        "evidence_missing"
      ]
    },
    "post_verify": {
      "type": "object",
      "additionalProperties": false,
      "required": ["gate_rerun_performed", "gate_passed"],
      "properties": {
        "gate_rerun_performed": { "type": "boolean" },
        "gate_passed": { "type": "boolean" },
        "gate_result_evidence_paths": {
          "type": "array",
          "items": { "type": "string", "minLength": 1 },
          "uniqueItems": true
        }
      }
    },
    "evidence_paths": {
      "type": "array",
      "items": { "type": "string", "minLength": 1 },
      "uniqueItems": true,
      "description": "Aggregate evidence (templates + post-verify)."
    }
  },
  "allOf": [
    {
      "if": {
        "properties": { "healed": { "const": true } },
        "required": ["healed"]
      },
      "then": {
        "properties": {
          "termination_reason": { "const": "sequence_success" },
          "post_verify": {
            "properties": {
              "gate_rerun_performed": { "const": true },
              "gate_passed": { "const": true }
            },
            "required": ["gate_rerun_performed", "gate_passed"]
          }
        },
        "required": ["termination_reason", "post_verify"]
      }
    },
    {
      "if": {
        "properties": { "termination_reason": { "const": "prereq_violation" } },
        "required": ["termination_reason"]
      },
      "then": {
        "properties": { "healed": { "const": false } },
        "required": ["healed"]
      }
    },
    {
      "if": {
        "properties": { "termination_reason": { "const": "template_failed" } },
        "required": ["termination_reason"]
      },
      "then": {
        "properties": { "healed": { "const": false } },
        "required": ["healed"]
      }
    }
  ]
}



Deterministic enforcement rules (runtime must enforce these, not “best effort”)


Ordering constraint: sequence.results[i].heal_template_id MUST equal sequence.ordered_heal_template_ids[i] for all executed steps (prefix alignment). If not, set termination_reason = evidence_missing and healed=false.

Fail-closed prereqs: if any result has status=prereq_violation, orchestration MUST stop immediately and set:
healed=false


termination_reason=prereq_violation
Downstream boolean definition: healed=true is allowed only when:


every executed template status=success

post_verify.gate_rerun_performed=true

post_verify.gate_passed=true

required_evidence_present=true
No matcher drift: FailureMode.matchers[] may only reference the enumerated matcher fields in the schema; adding new fields requires a schema bump.


If you want the next step after schemas: define a canonical error code taxonomy for error_codes[] (gate failures + heal failures) so fingerprints and matchers stay stable across repos and projects.
